// // This module implements a 32-bit wide, 2-to-1 demultiplexer. When the select signal S is 0, the output Z will reflect the value of input Y, and when S is 1, the output Z will take the value of input X.
module top_module(X,Y,S,Z);parameter N = 32; 


	input wire [N-1:0] X, Y; 
	input wire S; 
	output wire [N-1:0] Z; 

	assign Z = S ? Y : X; 


endmodule
